      out.write("\r\n");
      out.write("			<h3 id=\"modalDate\">Add Holiday</h3>\r\n");
      out.write("\r\n");
      out.write("			<input type=\"text\" id=\"holidayNameInput\" placeholder=\"Holiday Name\"\r\n");
      out.write("				style=\"width: 100%; padding: 8px; margin-top: 10px;\">\r\n");
