      out.write("	<!-- Toast Notification -->\r\n");
      out.write("	<div id=\"toast\" class=\"toast\"></div>\r\n");
      out.write("\r\n");
      out.write("	<script>\r\n");
      out.write("let today = new Date();\r\n");
      out.write("let currentMonth = today.getMonth();\r\n");
      out.write("let currentYear = today.getFullYear();\r\n");
      out.write("let selectedDate = \"\";\r\n");
      out.write("\r\n");
      out.write("/* ===== LOAD CALENDAR ===== */\r\n");
      out.write("function loadCalendar(){\r\n");
      out.write("\r\n");
      out.write("    const monthYear = document.getElementById(\"monthYear\");\r\n");
      out.write("    const tbody = document.querySelector(\"#calendar tbody\");\r\n");
      out.write("    tbody.innerHTML = \"\";\r\n");
      out.write("\r\n");
      out.write("    const months = [\"January\",\"February\",\"March\",\"April\",\"May\",\"June\",\r\n");
      out.write("                    \"July\",\"August\",\"September\",\"October\",\"November\",\"December\"];\r\n");
      out.write("\r\n");
      out.write("    monthYear.innerText = months[currentMonth] + \" \" + currentYear;\r\n");
      out.write("\r\n");
      out.write("    let firstDay = new Date(currentYear,currentMonth,1).getDay();\r\n");
      out.write("    let daysInMonth = new Date(currentYear,currentMonth+1,0).getDate();\r\n");
      out.write("\r\n");
      out.write("    fetch(\"getHolidays\")\r\n");
      out.write("    .then(r => r.json())\r\n");
      out.write("    .then(holidays => {\r\n");
      out.write("\r\n");
      out.write("        let holidayMap = {};\r\n");
      out.write("        holidays.forEach(h => {\r\n");
      out.write("            holidayMap[h.date] = h.name;\r\n");
      out.write("        });\r\n");
      out.write("\r\n");
      out.write("        let row = document.createElement(\"tr\");\r\n");
      out.write("\r\n");
      out.write("        for(let i=0;i<firstDay;i++){\r\n");
      out.write("            row.appendChild(document.createElement(\"td\"));\r\n");
      out.write("        }\r\n");
      out.write("\r\n");
      out.write("        for(let d=1; d<=daysInMonth; d++){\r\n");
      out.write("\r\n");
      out.write("            if(row.children.length === 7){\r\n");
      out.write("                tbody.appendChild(row);\r\n");
      out.write("                row = document.createElement(\"tr\");\r\n");
      out.write("            }\r\n");
      out.write("\r\n");
      out.write("            let cell = document.createElement(\"td\");\r\n");
      out.write("            cell.innerText = d;\r\n");
      out.write("\r\n");
      out.write("            let dayOfWeek = new Date(currentYear, currentMonth, d).getDay();\r\n");
      out.write("\r\n");
      out.write("            // Weekend Red\r\n");
      out.write("            if(dayOfWeek === 0 || dayOfWeek === 6){\r\n");
      out.write("                cell.classList.add(\"holiday\");\r\n");
      out.write("            }\r\n");
      out.write("\r\n");
      out.write("            // Today\r\n");
      out.write("            if(d === today.getDate() &&\r\n");
      out.write("               currentMonth === today.getMonth() &&\r\n");
      out.write("               currentYear === today.getFullYear()){\r\n");
      out.write("                cell.classList.add(\"today\");\r\n");
      out.write("            }\r\n");
      out.write("\r\n");
      out.write("            // DB Holiday\r\n");
      out.write("            let month = (currentMonth+1).toString().padStart(2,'0');\r\n");
      out.write("            let day = d.toString().padStart(2,'0');\r\n");
      out.write("            let fullDate = currentYear + \"-\" + month + \"-\" + day;\r\n");
      out.write("\r\n");
      out.write("            if(holidayMap[fullDate]){\r\n");
      out.write("                cell.classList.add(\"holiday\");\r\n");
      out.write("\r\n");
      out.write("                let div = document.createElement(\"div\");\r\n");
      out.write("                div.style.fontSize = \"11px\";\r\n");
      out.write("                div.style.marginTop = \"4px\";\r\n");
      out.write("                div.innerText = holidayMap[fullDate];\r\n");
      out.write("                cell.appendChild(div);\r\n");
      out.write("            }\r\n");
      out.write("\r\n");
      out.write("            row.appendChild(cell);\r\n");
      out.write("        }\r\n");
      out.write("\r\n");
      out.write("        tbody.appendChild(row);\r\n");
      out.write("    });\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("/* ===== MONTH CHANGE ===== */\r\n");
      out.write("function changeMonth(step){\r\n");
      out.write("    currentMonth += step;\r\n");
      out.write("    if(currentMonth < 0){ currentMonth = 11; currentYear--; }\r\n");
      out.write("    if(currentMonth > 11){ currentMonth = 0; currentYear++; }\r\n");
      out.write("    loadCalendar();\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("/* ===== CLICK DATE → OPEN MODAL ===== */\r\n");
      out.write("document.addEventListener(\"click\", function(e){\r\n");
      out.write("\r\n");
      out.write("    let cell = e.target.closest(\"#calendar td\");\r\n");
      out.write("    if(!cell) return;\r\n");
      out.write("\r\n");
      out.write("    let day = cell.childNodes[0].nodeValue.trim();\r\n");
      out.write("    if(day === \"\" || isNaN(day)) return;\r\n");
      out.write("\r\n");
      out.write("    const role = \"");
      out.print(session.getAttribute("role"));
      out.write("\";\r\n");
      out.write("    if(!role || role.toLowerCase() !== \"admin\") return;\r\n");
      out.write("\r\n");
      out.write("    let month = (currentMonth + 1).toString().padStart(2,'0');\r\n");
      out.write("    let d = day.toString().padStart(2,'0');\r\n");
      out.write("\r\n");
      out.write("    selectedDate = currentYear + \"-\" + month + \"-\" + d;\r\n");
      out.write("\r\n");
      out.write("    /* BLOCK PAST DATE */\r\n");
      out.write("    let todayStr = new Date().toISOString().split(\"T\")[0];\r\n");
      out.write("    if(selectedDate < todayStr){\r\n");
      out.write("        showToast(\"previous date not allowed\",\"error\");\r\n");
      out.write("        return;\r\n");
      out.write("    }\r\n");
